const inputData = $input.first().json; 
const texto_bruto = inputData.output || inputData.text || "";

const extraerTexto = (campo, fallback) => {
    const regex = new RegExp(`${campo}[:\\s]+([^\\n]+)`, 'i');
    const match = texto_bruto.match(regex);
    return match ? match[1].trim() : fallback;
};

// Extrae solo el PRIMER número de la lista para BigQuery
const extraerPrimerNumero = (campo, fallback) => {
    const texto = extraerTexto(campo, "");
    if (!texto) return fallback;
    const primerNumero = texto.split(',')[0].trim(); 
    return parseFloat(primerNumero.replace(',', '.')) || fallback;
};

// Extrae solo el PRIMER texto de una lista (Ej: "N, NE" -> "N")
const extraerPrimerTexto = (campo, fallback) => {
    const texto = extraerTexto(campo, "");
    if (!texto) return fallback;
    return texto.split(',')[0].trim() || fallback;
};

const reporte_limpio = texto_bruto.replace(/\[MOSTRAR_GRAFICO\][\s\S]*/i, "").trim();

return [{
    json: {
        // --- DATOS PARA BIGQUERY (datos_sectoriales) ---
        timestamp: new Date().toISOString(),
        session_id: inputData.session_id || `naval-${Date.now()}`,
        sector: "NAVAL", 

        puerto: extraerTexto("puerto", "S/D"),
        condiciones_mar: extraerTexto("condiciones_mar", "S/D"),
        viento_velocidad: extraerPrimerNumero("viento_velocidad", 0),
        viento_direccion: extraerPrimerTexto("viento_direccion", "VAR"), 
        temperatura_agua: extraerPrimerNumero("temperatura_agua", 20),
        altura_olas: extraerPrimerNumero("altura_olas", 0),
        visibilidad: extraerPrimerNumero("visibilidad", 10),

        ai_analysis: reporte_limpio,

        metadata: JSON.stringify({ 
            status: "success", 
            trigger_input: inputData.query || "Entrada Naval" 
        }),

        // --- DATOS PARA DJANGO Y CHART.JS (Con las listas completas) ---
        output: texto_bruto 
    }
}];
